// S1 = 1, S2 = 1 (baslangic degerleri)

// Surec P0:               // Surec P1:
wait(S1);                  wait(S2);
wait(S2);                  wait(S1);
  // kritik bolge            // kritik bolge
signal(S2);                signal(S1);
signal(S1);                signal(S2);

// Kilitlenme senaryosu:
// P0: wait(S1) -> S1=0 (basarili)
// P1: wait(S2) -> S2=0 (basarili)
// P0: wait(S2) -> S2=0, BEKLE! (P1 tutuyor)
// P1: wait(S1) -> S1=0, BEKLE! (P0 tutuyor)
// KILITLENME! Hicbiri ilerleyemez.

// S1 = 1, S2 = 1 (baslangic degerleri)

// Surec P0:               // Surec P1:
wait(S1);                  wait(S1);    // AYNI siralama!
wait(S2);                  wait(S2);
  // kritik bolge            // kritik bolge
signal(S2);                signal(S2);
signal(S1);                signal(S1);

// Her iki surec de semaforlari AYNI SIRADA istiyor.
